3	// Atributos de vértice recebidos como entrada ("in") pelo Vertex Shader.
4	// Veja a função BuildTrianglesAndAddToVirtualScene() em "main.cpp".
5	layout (location = 0) in vec4 model_coefficients;
6	layout (location = 1) in vec4 normal_coefficients;
7	layout (location = 2) in vec2 texture_coefficients;
8	
9	// Matrizes computadas no código C++ e enviadas para a GPU
10	uniform mat4 model;
11	uniform mat4 view;
12	uniform mat4 projection;
13	
14	// Atributos de vértice que serão gerados como saída ("out") pelo Vertex Shader.
15	// ** Estes serão interpolados pelo rasterizador! ** gerando, assim, valores
16	// para cada fragmento, os quais serão recebidos como entrada pelo Fragment
17	// Shader. Veja o arquivo "shader_fragment.glsl".
18	out vec4 position_world;
19	out vec4 position_model;
20	out vec4 normal;
21	out vec2 texcoords;
22	
23	void main()
24	{
25	    // A variável gl_Position define a posição final de cada vértice
26	    // OBRIGATORIAMENTE em "normalized device coordinates" (NDC), onde cada
27	    // coeficiente estará entre -1 e 1 após divisão por w.
28	    // Veja {+NDC2+}.
29	    //
30	    // O código em "main.cpp" define os vértices dos modelos em coordenadas
31	    // locais de cada modelo (array model_coefficients). Abaixo, utilizamos
32	    // operações de modelagem, definição da câmera, e projeção, para computar
33	    // as coordenadas finais em NDC (variável gl_Position). Após a execução
34	    // deste Vertex Shader, a placa de vídeo (GPU) fará a divisão por W. Veja
35	    // slides 41-67 e 69-86 do documento Aula_09_Projecoes.pdf.
36	
37	    gl_Position = projection * view * model * model_coefficients;
38	
39	    // Como as variáveis acima  (tipo vec4) são vetores com 4 coeficientes,
40	    // também é possível acessar e modificar cada coeficiente de maneira
41	    // independente. Esses são indexados pelos nomes x, y, z, e w (nessa
42	    // ordem, isto é, 'x' é o primeiro coeficiente, 'y' é o segundo, ...):
43	    //
44	    //     gl_Position.x = model_coefficients.x;
45	    //     gl_Position.y = model_coefficients.y;
46	    //     gl_Position.z = model_coefficients.z;
47	    //     gl_Position.w = model_coefficients.w;
48	    //
49	
50	    // Agora definimos outros atributos dos vértices que serão interpolados pelo
51	    // rasterizador para gerar atributos únicos para cada fragmento gerado.
52	
53	    // Posição do vértice atual no sistema de coordenadas global (World).
54	    position_world = model * model_coefficients;
55	
56	    // Posição do vértice atual no sistema de coordenadas local do modelo.
57	    position_model = model_coefficients;
58	
59	    // Normal do vértice atual no sistema de coordenadas global (World).
60	    // Veja slides 123-151 do documento Aula_07_Transformacoes_Geometricas_3D.pdf.
61	    normal = inverse(transpose(model)) * normal_coefficients;
62	    normal.w = 0.0;
63	
64	    // Coordenadas de textura obtidas do arquivo OBJ (se existirem!)
65	    texcoords = texture_coefficients;
66	}
