442	    vec4 h = normalize(v + l);
443	    float n_dot_h = max(0.0, dot(n, h));
444	
445	    // Eleva na potência de "shininess" 
446	    float specular_intensity = pow(n_dot_h, 32.0); 
447	    
448	    // Multiplicamos pela cor da luz (branco puro) e pelo Ks_map
449	    vec3 specular_color = vec3(1.0, 1.0, 1.0) * specular_intensity * Ks_map;
