1429	// Função callback chamada sempre que o usuário movimentar o cursor do mouse em
1430	// cima da janela OpenGL.
1431	void CursorPosCallback(GLFWwindow* window, double xpos, double ypos)
1432	{
1433	    // Abaixo executamos o seguinte: caso o botão esquerdo do mouse esteja
1434	    // pressionado, computamos quanto que o mouse se movimento desde o último
1435	    // instante de tempo, e usamos esta movimentação para atualizar os
1436	    // parâmetros que definem a posição da câmera dentro da cena virtual.
1437	    // Assim, temos que o usuário consegue controlar a câmera.
1438	
1439	    if (g_LeftMouseButtonPressed)
1440	    {
1441	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1442	        float dx = xpos - g_LastCursorPosX;
1443	        float dy = ypos - g_LastCursorPosY;
1444	    
1445	        // Atualizamos parâmetros da câmera com os deslocamentos
1446	        g_CameraTheta -= 0.01f*dx;
1447	        g_CameraPhi   += 0.01f*dy;
1448	    
1449	        // Em coordenadas esféricas, o ângulo phi deve ficar entre -pi/2 e +pi/2.
1450	        float phimax = 3.141592f/2;
1451	        float phimin = -phimax;
1452	    
1453	        if (g_CameraPhi > phimax)
1454	            g_CameraPhi = phimax;
1455	    
1456	        if (g_CameraPhi < phimin)
1457	            g_CameraPhi = phimin;
1458	    
1459	        // Atualizamos as variáveis globais para armazenar a posição atual do
1460	        // cursor como sendo a última posição conhecida do cursor.
1461	        g_LastCursorPosX = xpos;
1462	        g_LastCursorPosY = ypos;
1463	    }
1464	
1465	    if (g_RightMouseButtonPressed)
1466	    {
1467	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1468	        float dx = xpos - g_LastCursorPosX;
1469	        float dy = ypos - g_LastCursorPosY;
1470	    
1471	        // Atualizamos parâmetros da antebraço com os deslocamentos
1472	        g_ForearmAngleZ -= 0.01f*dx;
1473	        g_ForearmAngleX += 0.01f*dy;
1474	    
1475	        // Atualizamos as variáveis globais para armazenar a posição atual do
1476	        // cursor como sendo a última posição conhecida do cursor.
1477	        g_LastCursorPosX = xpos;
1478	        g_LastCursorPosY = ypos;
1479	    }
1480	
1481	    if (g_MiddleMouseButtonPressed)
1482	    {
1483	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1484	        float dx = xpos - g_LastCursorPosX;
1485	        float dy = ypos - g_LastCursorPosY;
1486	    
1487	        // Atualizamos parâmetros da antebraço com os deslocamentos
1488	        g_TorsoPositionX += 0.01f*dx;
1489	        g_TorsoPositionY -= 0.01f*dy;
1490	    
1491	        // Atualizamos as variáveis globais para armazenar a posição atual do
1492	        // cursor como sendo a última posição conhecida do cursor.
1493	        g_LastCursorPosX = xpos;
1494	        g_LastCursorPosY = ypos;
1495	    }
1496	}
