1498	// Função callback chamada sempre que o usuário movimenta a "rodinha" do mouse.
1499	void ScrollCallback(GLFWwindow* window, double xoffset, double yoffset)
1500	{
1501	    // Atualizamos a distância da câmera para a origem utilizando a
1502	    // movimentação da "rodinha", simulando um ZOOM.
1503	    g_CameraDistance -= 0.1f*yoffset;
1504	
1505	    // Uma câmera look-at nunca pode estar exatamente "em cima" do ponto para
1506	    // onde ela está olhando, pois isto gera problemas de divisão por zero na
1507	    // definição do sistema de coordenadas da câmera. Isto é, a variável abaixo
1508	    // nunca pode ser zero. Versões anteriores deste código possuíam este bug,
1509	    // o qual foi detectado pelo aluno Vinicius Fraga (2017/2).
1510	    const float verysmallnumber = std::numeric_limits<float>::epsilon();
1511	    if (g_CameraDistance < verysmallnumber)
1512	        g_CameraDistance = verysmallnumber;
1513	}
