1517	// Definição da função que será chamada sempre que o usuário pressionar alguma
1518	// tecla do teclado. Veja http://www.glfw.org/docs/latest/input_guide.html#input_key
1519	void KeyCallback(GLFWwindow* window, int key, int scancode, int action, int mod)
1520	{
1521	    // =======================
1522	    // Não modifique esta chamada! Ela é utilizada para correção automatizada dos
1523	    // laboratórios. Deve ser sempre o primeiro comando desta função KeyCallback().
1524	    Correcao_KeyCallback(key, action, mod);
1525	    // =======================
1526	
1527	    // Se o usuário pressionar a tecla ESC, fechamos a janela.
1528	    if (key == GLFW_KEY_ESCAPE && action == GLFW_PRESS)
1529	        glfwSetWindowShouldClose(window, GL_TRUE);
1530	    
1531	    // O código abaixo implementa a seguinte lógica:
1532	    //   Se apertar tecla X       então g_AngleX += delta;
1533	    //   Se apertar tecla shift+X então g_AngleX -= delta;
1534	    //   Se apertar tecla Y       então g_AngleY += delta;
1535	    //   Se apertar tecla shift+Y então g_AngleY -= delta;
1536	    //   Se apertar tecla Z       então g_AngleZ += delta;
1537	    //   Se apertar tecla shift+Z então g_AngleZ -= delta;
1538	
1539	    float delta = 3.141592 / 16; // 22.5 graus, em radianos.
1540	
1541	    if (key == GLFW_KEY_X && action == GLFW_PRESS)
1542	    {
1543	        g_AngleX += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1544	    }
1545	
1546	    if (key == GLFW_KEY_Y && action == GLFW_PRESS)
1547	    {
1548	        g_AngleY += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1549	    }
1550	    if (key == GLFW_KEY_Z && action == GLFW_PRESS)
1551	    {
1552	        g_AngleZ += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1553	    }
1554	
1555	    // Se o usuário apertar a tecla espaço, resetamos os ângulos de Euler para zero.
1556	    if (key == GLFW_KEY_SPACE && action == GLFW_PRESS)
1557	    {
1558	        g_AngleX = 0.0f;
1559	        g_AngleY = 0.0f;
1560	        g_AngleZ = 0.0f;
1561	        g_ForearmAngleX = 0.0f;
1562	        g_ForearmAngleZ = 0.0f;
1563	        g_TorsoPositionX = 0.0f;
1564	        g_TorsoPositionY = 0.0f;
1565	    }
1566	
1567	    // Se o usuário apertar a tecla P, utilizamos projeção perspectiva.
1568	    if (key == GLFW_KEY_P && action == GLFW_PRESS)
1569	    {
1570	        g_UsePerspectiveProjection = true;
1571	    }
1572	
1573	    // Se o usuário apertar a tecla O, utilizamos projeção ortográfica.
1574	    if (key == GLFW_KEY_O && action == GLFW_PRESS)
1575	    {
1576	        g_UsePerspectiveProjection = false;
1577	    }
1578	
1579	    // Se o usuário apertar a tecla H, fazemos um "toggle" do texto informativo mostrado na tela.
1580	    if (key == GLFW_KEY_H && action == GLFW_PRESS)
1581	    {
1582	        g_ShowInfoText = !g_ShowInfoText;
1583	    }
1584	
1585	    // Se o usuário apertar a tecla R, recarregamos os shaders dos arquivos "shader_fragment.glsl" e "shader_vertex.glsl".
1586	    if (key == GLFW_KEY_R && action == GLFW_PRESS)
1587	    {
1588	        LoadShadersFromFiles();
1589	        fprintf(stdout,"Shaders recarregados!\n");
1590	        fflush(stdout);
1591	    }
1592	}
