1693	// second).
1694	void TextRendering_ShowFramesPerSecond(GLFWwindow* window)
1695	{
1696	    if ( !g_ShowInfoText )
1697	        return;
1698	
1699	    // Variáveis estáticas (static) mantém seus valores entre chamadas
1700	    // subsequentes da função!
1701	    static float old_seconds = (float)glfwGetTime();
1702	    static int   ellapsed_frames = 0;
1703	    static char  buffer[20] = "?? fps";
1704	    static int   numchars = 7;
1705	
1706	    ellapsed_frames += 1;
1707	
1708	    // Recuperamos o número de segundos que passou desde a execução do programa
1709	    float seconds = (float)glfwGetTime();
1710	
1711	    // Número de segundos desde o último cálculo do fps
1712	    float ellapsed_seconds = seconds - old_seconds;
1713	
1714	    if ( ellapsed_seconds > 1.0f )
1715	    {
1716	        numchars = snprintf(buffer, 20, "%.2f fps", ellapsed_frames / ellapsed_seconds);
1717	    
1718	        old_seconds = seconds;
1719	        ellapsed_frames = 0;
1720	    }
1721	
1722	    float lineheight = TextRendering_LineHeight(window);
1723	    float charwidth = TextRendering_CharWidth(window);
